#include <stdio.h>
#include <math.h>

int isSquare(int n) {
    int sqrt_n = sqrt(n);
    return sqrt_n * sqrt_n == n;
}

int canWin(int n, int* arr, int* z) {
    if (n == 0) return 0;
    for (int i = 0; i < n; i++) {
        int temp = arr[i];
        arr[i] = -1;
        *z += temp;
        if (!isSquare(*z) || !canWin(n - 1, arr, z)) {
            arr[i] = temp;
            *z -= temp;
            return 1;
        }
        arr[i] = temp;
        *z -= temp;
    }
    return 0;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int* arr = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int z = 0;
        if (canWin(n, arr, &z)) {
            printf("Ghayeeth\n");
        } else {
            printf("Siroj\n");
        }
        free(arr);
    }
    return 0;
}

